<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Personal Expense Tracker</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; background: #f5f7fa; color: #333; line-height: 1.6; padding: 24px; }
  h1 { text-align: center; margin-bottom: 24px; font-size: 1.8rem; }

  .container { max-width: 900px; margin: 0 auto; }

  /* Form */
  .form-card { background: #fff; border-radius: 8px; padding: 24px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; }
  .form-row { display: flex; gap: 16px; align-items: flex-end; flex-wrap: wrap; }
  .form-group { display: flex; flex-direction: column; flex: 1; min-width: 140px; }
  .form-group label { font-size: .85rem; font-weight: 600; margin-bottom: 4px; color: #555; }
  input, select { padding: 8px 12px; border: 1px solid #ccc; border-radius: 4px; font-size: .95rem; outline: none; transition: border-color .2s; }
  input:focus, select:focus { border-color: #4a90d9; }
  button#add-expense { padding: 8px 20px; background: #4a90d9; color: #fff; border: none; border-radius: 4px; font-size: .95rem; cursor: pointer; white-space: nowrap; transition: background .2s; }
  button#add-expense:hover { background: #357abd; }

  /* Error */
  #form-error { color: #d9534f; font-size: .85rem; margin-top: 10px; min-height: 1.2em; }

  /* Filters */
  .filters-card { background: #fff; border-radius: 8px; padding: 20px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; display: flex; gap: 16px; align-items: center; flex-wrap: wrap; }
  .filters-card label { font-size: .85rem; font-weight: 600; color: #555; white-space: nowrap; margin-right: 4px; }

  /* Summary */
  .summary-bar { background: #fff; border-radius: 8px; padding: 20px; box-shadow: 0 1px 3px rgba(0,0,0,.1); margin-bottom: 24px; display: flex; justify-content: space-between; align-items: center; flex-wrap: wrap; gap: 12px; }
  .total-label { font-size: .9rem; color: #555; }
  #total { font-size: 1.6rem; font-weight: 700; color: #4a90d9; }

  /* Category totals */
  .cat-totals { display: flex; gap: 12px; flex-wrap: wrap; margin-top: 8px; }
  .cat-total { background: #eef3fa; border-radius: 6px; padding: 6px 14px; font-size: .9rem; color: #555; }

  /* Expense list */
  .expense-list { background: #fff; border-radius: 8px; box-shadow: 0 1px 3px rgba(0,0,0,.1); overflow: hidden; }
  .expense-header { padding: 14px 20px; font-weight: 600; color: #555; background: #fafbfc; border-bottom: 1px solid #eee; display: flex; justify-content: space-between; align-items: center; }
  .expense-list ul { list-style: none; }
  .expense { display: flex; justify-content: space-between; align-items: center; padding: 14px 20px; border-bottom: 1px solid #eee; transition: background .15s; }
  .expense:last-child { border-bottom: none; }
  .expense:hover { background: #f9fafb; }
  .exp-info { display: flex; align-items: center; gap: 12px; }
  .exp-amount { font-weight: 700; color: #d9534f; min-width: 80px; text-align: right; }
  .exp-category { background: #eef3fa; padding: 2px 10px; border-radius: 12px; font-size: .8rem; color: #555; white-space: nowrap; }
  .exp-date { color: #888; font-size: .85rem; }
  .exp-del { background: none; border: none; color: #d9534f; cursor: pointer; font-size: 1.2rem; padding: 4px 8px; border-radius: 4px; transition: background .15s; line-height: 1; }
  .exp-del:hover { background: #fce4e6; }

  /* Empty state */
  .empty-state { text-align: center; color: #999; padding: 30px; font-size: .95rem; }
</style>
</head>
<body>
<div class="container">
  <h1>Expense Tracker</h1>

  <!-- Entry Form -->
  <div class="form-card">
    <form id="expense-form" onsubmit="handleAdd(event)">
      <div class="form-row">
        <div class="form-group">
          <label for="amount">Amount ($)</label>
          <input type="number" id="amount" placeholder="0.00" step="0.01" min="0.01">
        </div>
        <div class="form-group">
          <label for="category">Category</label>
          <select id="category">
            <option value="groceries">Groceries</option>
            <option value="transport">Transport</option>
            <option value="bills">Bills</option>
            <option value="fun">Fun</option>
          </select>
        </div>
        <div class="form-group">
          <label for="date">Date</label>
          <input type="date" id="date">
        </div>
        <div class="form-group">
          <label for="note">Note (optional)</label>
          <input type="text" id="note" placeholder="Optional note...">
        </div>
        <button type="submit" id="add-expense">Add Expense</button>
      </div>
      <div id="form-error"></div>
    </form>
  </div>

  <!-- Filters -->
  <div class="filters-card">
    <label for="filter-category">Category:</label>
    <select id="filter-category" onchange="applyFilters()">
      <option value="all">All</option>
      <option value="groceries">Groceries</option>
      <option value="transport">Transport</option>
      <option value="bills">Bills</option>
      <option value="fun">Fun</option>
    </select>

    <label for="filter-from">From:</label>
    <input type="date" id="filter-from" onchange="applyFilters()">

    <label for="filter-to">To:</label>
    <input type="date" id="filter-to" onchange="applyFilters()">
  </div>

  <!-- Summary -->
  <div class="summary-bar">
    <span class="total-label">Total (visible):</span>
    <span id="total">$0.00</span>
    <div class="cat-totals" id="cat-totals"></div>
  </div>

  <!-- Expense List -->
  <div class="expense-list">
    <div class="expense-header">
      <span>Expenses (newest first)</span>
      <button onclick="clearAll()" style="background:none;border:1px solid #ccc;color:#888;padding:4px 10px;border-radius:4px;cursor:pointer;font-size:.8rem;">Clear All</button>
    </div>
    <ul id="expense-list"></ul>
  </div>
</div>

<script>
(function() {
  const STORAGE_KEY = 'expenseTracker';
  let expenses = [];

  // --- Persistence ---
  function loadExpenses() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      if (raw) {
        expenses = JSON.parse(raw);
      }
    } catch(e) {
      expenses = [];
    }
  }

  function saveExpenses() {
    localStorage.setItem(STORAGE_KEY, JSON.stringify(expenses));
  }

  // --- Form handling ---
  function handleAdd(e) {
    e.preventDefault();
    const amountInput = document.getElementById('amount');
    const dateInput = document.getElementById('date');
    const errorEl = document.getElementById('form-error');

    let amountStr = amountInput.value.trim();
    if (!amountStr) {
      showError('Please enter an amount.');
      return;
    }
    let amount = parseFloat(amountStr);
    if (isNaN(amount)) {
      showError('Amount must be a valid number.');
      return;
    }
    if (amount <= 0) {
      showError('Amount must be greater than zero.');
      return;
    }

    const dateVal = dateInput.value.trim();
    if (!dateVal) {
      showError('Please select a date.');
      return;
    }

    // Valid submission
    errorEl.textContent = '';
    amountInput.value = '';
    resetForm();

    expenses.push({
      id: Date.now() + Math.random(),
      amount,
      category: document.getElementById('category').value,
      date: dateVal,
      note: document.getElementById('note').value.trim()
    });

    saveExpenses();
    renderAll();
  }

  function showError(msg) {
    const errorEl = document.getElementById('form-error');
    errorEl.textContent = msg;
  }

  function resetForm() {
    document.getElementById('amount').value = '';
    document.getElementById('note').value = '';
    document.getElementById('date').value = '';
  }

  // --- Rendering ---
  function renderAll() {
    renderList();
    renderSummary();
  }

  function renderList() {
    const listEl = document.getElementById('expense-list');
    const filtered = getFilteredExpenses();

    if (filtered.length === 0) {
      listEl.innerHTML = '<li class="empty-state">No expenses to display.</li>';
      return;
    }

    // Newest first
    filtered.sort((a, b) => new Date(b.date) - new Date(a.date));

    let html = '';
    for (const exp of filtered) {
      html += '<li class="expense">' +
        '<div class="exp-info">' +
          '<span class="exp-amount">$' + formatNum(exp.amount) + '</span>' +
          '<span class="exp-category">' + exp.category.charAt(0).toUpperCase() + exp.category.slice(1) + '</span>' +
          '<span class="exp-date">' + formatDate(exp.date) + '</span>' +
        '</div>' +
        '<button class="exp-del" onclick="deleteExpense(' + JSON.stringify(exp.id) + ')">&times;</button>' +
      '</li>';
    }
    listEl.innerHTML = html;
  }

  function renderSummary() {
    const filtered = getFilteredExpenses();
    const total = filtered.reduce((sum, e) => sum + e.amount, 0);
    document.getElementById('total').textContent = '$' + formatNum(total);

    // Per-category totals (only for categories that have visible expenses)
    const catTotalsEl = document.getElementById('cat-totals');
    const catsWithExpenses = {};
    for (const e of filtered) {
      if (!catsWithExpenses[e.category]) catsWithExpenses[e.category] = 0;
      catsWithExpenses[e.category] += e.amount;
    }

    catTotalsEl.innerHTML = '';
    for (const [cat, total] of Object.entries(catsWithExpenses)) {
      const el = document.createElement('div');
      el.className = 'cat-total';
      el.setAttribute('data-cat', cat);
      el.textContent = cat.charAt(0).toUpperCase() + cat.slice(1) + ': $' + formatNum(total);
      catTotalsEl.appendChild(el);
    }
  }

  // --- Filtering ---
  function getFilteredExpenses() {
    const catFilter = document.getElementById('filter-category').value;
    const fromVal = document.getElementById('filter-from').value.trim();
    const toVal = document.getElementById('filter-to').value.trim();

    return expenses.filter(e => {
      if (catFilter !== 'all' && e.category !== catFilter) return false;
      if (fromVal && e.date < fromVal) return false;
      if (toVal && e.date > toVal) return false;
      return true;
    });
  }

  function applyFilters() {
    renderAll();
  }

  // --- Actions ---
  window.deleteExpense = function(id) {
    expenses = expenses.filter(e => e.id !== id);
    saveExpenses();
    renderAll();
  };

  window.clearAll = function() {
    if (confirm('Delete all expenses?')) {
      expenses = [];
      saveExpenses();
      renderAll();
    }
  };

  // --- Helpers ---
  function formatNum(n) {
    return n.toFixed(2);
  }

  function formatDate(d) {
    const parts = d.split('-');
    return parts[0] + '/' + parts[1] + '/' + parts[2];
  }

  // Initialize: set today's date as default in form, load data
  document.getElementById('date').valueAsDate = new Date();
  loadExpenses();
  renderAll();
})();
</script>
</body>
</html>
